import sys

OPS = {"+", "-", "*"}

def solve_case(tokens):
    stack = []
    for tok in tokens:
        if tok in OPS:
            b = stack.pop()
            a = stack.pop()
            if tok == "+":
                stack.append(a + b)
            elif tok == "-":
                stack.append(a - b)
            else:
                stack.append(a * b)
        else:
            stack.append(int(tok))
    return stack[0]

def main():
    lines = sys.stdin.read().splitlines()
    t = int(lines[0])
    out = []
    for i in range(1, t + 1):
        out.append(str(solve_case(lines[i].split())))
    sys.stdout.write("\n".join(out) + "\n")

main()
